2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! CUDA context management (primary context, RAII).
7	//!
8	//! [`CudaContext`] retains the **primary context** for a given device ordinal
9	//! via `cuDevicePrimaryCtxRetain` and releases it on [`Drop`]. The primary
10	//! context is shared across the process; multiple `CudaContext` instances for
11	//! the same device share the same underlying `CUcontext`.
12	//!
13	//! # Thread binding
14	//!
15	//! CUDA driver calls are context-scoped and thread-local. [`CudaContext`]
16	//! transparently calls `cuCtxSetCurrent` before any driver operation, so
17	//! callers do not need to manage the context stack manually.
18	
19	use crate::error::{DriverError, IntoResult};
20	use crate::launch::DeviceLaunchLimits;
21	use crate::stream::CudaStream;
22	use std::ffi::c_int;
23	use std::mem::MaybeUninit;
24	use std::sync::Arc;
25	use std::sync::atomic::{AtomicBool, AtomicU32, AtomicUsize, Ordering};
26	
27	/// Owns a reference to a CUDA device's primary context.
28	///
29	/// Created via [`CudaContext::new`] and typically held in an `Arc` so streams,
30	/// events, and modules can share the same context. Dropping the last reference
31	/// releases the primary context (`cuDevicePrimaryCtxRelease`).
32	///
33	/// Tracks live stream count and accumulated error state atomically for
34	/// cross-thread diagnostics.
35	#[derive(Debug)]
36	pub struct CudaContext {
37	    /// Raw CUDA device handle (`CUdevice`).
38	    pub(crate) cu_device: cuda_bindings::CUdevice,
39	    /// Raw CUDA context handle (`CUcontext`). Set to null on drop.
40	    pub(crate) cu_ctx: cuda_bindings::CUcontext,
41	    /// Zero-based device ordinal passed to [`CudaContext::new`].
42	    pub(crate) ordinal: usize,
43	    /// Number of live [`CudaStream`] instances sharing this context.
44	    pub(crate) num_streams: AtomicUsize,
45	    /// When `true`, the first [`new_stream`](CudaContext::new_stream) call
46	    /// synchronizes the context to establish a clean ordering baseline.
47	    pub(crate) event_tracking: AtomicBool,
48	    /// Sticky error state recorded by [`record_err`](CudaContext::record_err).
49	    /// Stores the raw `CUresult` value, or `0` if no error.
50	    pub(crate) error_state: AtomicU32,
51	}
52	
53	/// # Safety
54	///
55	/// `CUdevice` and `CUcontext` are process-wide handles. All mutable state
56	/// (`num_streams`, `event_tracking`, `error_state`) uses atomics. The CUDA
57	/// driver itself is thread-safe for distinct contexts, and the
58	/// [`bind_to_thread`](CudaContext::bind_to_thread) mechanism ensures the
59	/// correct context is current before each call.
60	unsafe impl Send for CudaContext {}
61	/// See [`Send`] impl.
62	unsafe impl Sync for CudaContext {}
63	
64	/// Releases the primary context on drop.
65	///
66	/// Binds the context to the current thread first (required by
67	/// `cuDevicePrimaryCtxRelease`). Errors during teardown are recorded via
68	/// [`record_err`](CudaContext::record_err) rather than panicking.
69	impl Drop for CudaContext {
70	    fn drop(&mut self) {
71	        self.record_err(self.bind_to_thread());
72	        let ctx = std::mem::replace(&mut self.cu_ctx, std::ptr::null_mut());
73	        if !ctx.is_null() {
74	            self.record_err(unsafe {
75	                cuda_bindings::cuDevicePrimaryCtxRelease_v2(self.cu_device).result()
76	            });
77	        }
78	    }
79	}
80	
81	/// Equality is based on device handle, context handle, and ordinal.
82	impl PartialEq for CudaContext {
83	    fn eq(&self, other: &Self) -> bool {
84	        self.cu_device == other.cu_device
85	            && self.cu_ctx == other.cu_ctx
86	            && self.ordinal == other.ordinal
87	    }
88	}
89	impl Eq for CudaContext {}
90	
91	impl CudaContext {
92	    fn device_attribute(
93	        &self,
94	        attribute: cuda_bindings::CUdevice_attribute,
95	    ) -> Result<u32, DriverError> {
96	        self.bind_to_thread()?;
97	        let mut value = MaybeUninit::uninit();
98	        unsafe {
99	            cuda_bindings::cuDeviceGetAttribute(value.as_mut_ptr(), attribute, self.cu_device)
100	                .result()?;
101	            u32::try_from(value.assume_init())
102	                .map_err(|_| DriverError(cuda_bindings::cudaError_enum_CUDA_ERROR_INVALID_VALUE))
103	        }
104	    }
105	
106	    /// Creates a new context for the device at `ordinal`.
107	    ///
108	    /// Calls [`cuInit`](crate::init), obtains the device handle, retains the
109	    /// primary context, and binds it to the calling thread. Returns the context
110	    /// wrapped in an `Arc` for shared ownership across streams, events, and
111	    /// modules.
112	    pub fn new(ordinal: usize) -> Result<Arc<Self>, DriverError> {
113	        unsafe { crate::init(0)? };
114	
115	        let cu_device = unsafe {
116	            let mut cu_device = MaybeUninit::uninit();
117	            cuda_bindings::cuDeviceGet(cu_device.as_mut_ptr(), ordinal as c_int).result()?;
118	            cu_device.assume_init()
119	        };
120	
121	        let cu_ctx = unsafe {
122	            let mut cu_ctx = MaybeUninit::uninit();
123	            cuda_bindings::cuDevicePrimaryCtxRetain(cu_ctx.as_mut_ptr(), cu_device).result()?;
124	            cu_ctx.assume_init()
125	        };
126	
127	        let ctx = Arc::new(CudaContext {
128	            cu_device,
129	            cu_ctx,
130	            ordinal,
131	            num_streams: AtomicUsize::new(0),
132	            event_tracking: AtomicBool::new(true),
133	            error_state: AtomicU32::new(0),
134	        });
135	        ctx.bind_to_thread()?;
136	        Ok(ctx)
137	    }
138	
139	    /// Returns the zero-based device ordinal.
140	    pub fn ordinal(&self) -> usize {
141	        self.ordinal
142	    }
143	
144	    /// Returns the raw `CUdevice` handle.
145	    pub fn cu_device(&self) -> cuda_bindings::CUdevice {
146	        self.cu_device
147	    }
148	
149	    /// Returns the raw `CUcontext` handle.
150	    pub fn cu_ctx(&self) -> cuda_bindings::CUcontext {
151	        self.cu_ctx
152	    }
153	
154	    /// Binds this context to the calling thread if not already current.
155	    ///
156	    /// Checks [`check_err`](Self::check_err) first and propagates any sticky
157	    /// error. Skips the `cuCtxSetCurrent` call when the context is already
158	    /// bound, avoiding an unnecessary driver round-trip.
159	    ///
160	    /// Most methods on [`CudaStream`], [`CudaEvent`](crate::CudaEvent), and
161	    /// [`CudaModule`](crate::CudaModule) call this internally.
162	    ///
163	    /// CUcontext is the backing runtime object, and CUmodule / CUfunction / CUstream
164	    /// are opaque handles to objects created under that context. bind_to_thread()
165	    /// makes that context, the one, the current host thread is operating against.
166	    /// If the thread is currently bound to some other context, using those handles
167	    /// can fail.
168	    pub fn bind_to_thread(&self) -> Result<(), DriverError> {
169	        self.check_err()?;
170	        let mut current = MaybeUninit::uninit();
171	        unsafe {
172	            cuda_bindings::cuCtxGetCurrent(current.as_mut_ptr()).result()?;
173	            let current = current.assume_init();
174	            if current.is_null() || current != self.cu_ctx {
175	                cuda_bindings::cuCtxSetCurrent(self.cu_ctx).result()?;
176	            }
177	        }
178	        Ok(())
179	    }
180	
181	    /// Blocks the calling thread until all preceding work in this context
182	    /// completes.
183	    ///
184	    /// Binds the context first, then calls `cuCtxSynchronize`.
185	    pub fn synchronize(&self) -> Result<(), DriverError> {
186	        self.bind_to_thread()?;
187	        unsafe { cuda_bindings::cuCtxSynchronize() }.result()
188	    }
189	
190	    /// Returns a handle to the per-context default stream (stream `0`).
191	    ///
192	    /// The default stream implicitly synchronizes with all blocking streams in
193	    /// the same context. The returned [`CudaStream`] holds a null `CUstream`
194	    /// pointer, which the driver interprets as the default stream.
195	    pub fn default_stream(self: &Arc<Self>) -> Arc<CudaStream> {
196	        Arc::new(CudaStream {
197	            cu_stream: std::ptr::null_mut(),
198	            ctx: self.clone(),
199	        })
200	    }
201	
202	    /// Creates a new non-blocking stream in this context.
203	    ///
204	    /// The stream is created with `CU_STREAM_NON_BLOCKING`, so it does not
205	    /// implicitly synchronize with the default stream.
206	    ///
207	    /// On the first call (when `num_streams` transitions from 0 to 1), the
208	    /// context is synchronized to establish a clean ordering baseline if
209	    /// `event_tracking` is enabled.
210	    pub fn new_stream(self: &Arc<Self>) -> Result<Arc<CudaStream>, DriverError> {
211	        self.bind_to_thread()?;
212	        let prev = self.num_streams.fetch_add(1, Ordering::Relaxed);
213	        if prev == 0 && self.event_tracking.load(Ordering::Relaxed) {
214	            self.synchronize()?;
215	        }
216	        let mut cu_stream = MaybeUninit::uninit();
217	        let cu_stream = unsafe {
218	            cuda_bindings::cuStreamCreate(
219	                cu_stream.as_mut_ptr(),
220	                cuda_bindings::CUstream_flags_enum_CU_STREAM_NON_BLOCKING,
221	            )
222	            .result()?;
223	            cu_stream.assume_init()
224	        };
225	        Ok(Arc::new(CudaStream {
226	            cu_stream,
227	            ctx: self.clone(),
228	        }))
229	    }
230	
231	    /// Queries the device's marketing name (e.g. `"NVIDIA GeForce RTX 5090"`).
232	    ///
233	    /// Wraps `cuDeviceGetName` with a 256-byte buffer (driver guarantees
234	    /// the name fits in 256 bytes including the trailing NUL). Returns the
235	    /// decoded UTF-8 string with any trailing NULs stripped.
236	    pub fn device_name(&self) -> Result<String, DriverError> {
237	        self.bind_to_thread()?;
238	        let mut buf = [0; 256];
239	        unsafe {
240	            cuda_bindings::cuDeviceGetName(buf.as_mut_ptr(), buf.len() as c_int, self.cu_device)
241	                .result()?;
242	        }
243	        let bytes: Vec<u8> = buf
244	            .iter()
245	            .take_while(|&&c| c != 0)
246	            .map(|&c| c as u8)
247	            .collect();
248	        Ok(String::from_utf8_lossy(&bytes).into_owned())
249	    }
250	
251	    /// Queries the compute capability (SM version) of the device.
252	    ///
253	    /// Returns `(major, minor)` -- e.g. `(9, 0)` for Hopper H100.
254	    pub fn compute_capability(&self) -> Result<(i32, i32), DriverError> {
255	        self.bind_to_thread()?;
256	        let mut major = MaybeUninit::uninit();
257	        let mut minor = MaybeUninit::uninit();
258	        unsafe {
259	            cuda_bindings::cuDeviceGetAttribute(
260	                major.as_mut_ptr(),
261	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_COMPUTE_CAPABILITY_MAJOR,
262	                self.cu_device,
263	            )
264	            .result()?;
265	            cuda_bindings::cuDeviceGetAttribute(
266	                minor.as_mut_ptr(),
267	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_COMPUTE_CAPABILITY_MINOR,
268	                self.cu_device,
269	            )
270	            .result()?;
271	            Ok((major.assume_init(), minor.assume_init()))
272	        }
273	    }
274	
275	    /// Queries dimension, thread-count, and portable shared-memory launch
276	    /// limits for this device.
277	    ///
278	    /// Cooperative and cluster capabilities are deliberately not queried
279	    /// here. Typed launch preparation asks for those newer attributes only
280	    /// when the kernel contract requires the corresponding launch mode.
281	    pub fn launch_limits(&self) -> Result<DeviceLaunchLimits, DriverError> {
282	        Ok(DeviceLaunchLimits {
283	            max_threads_per_block: self.device_attribute(
284	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_THREADS_PER_BLOCK,
285	            )?,
286	            max_block_dim: (
287	                self.device_attribute(
288	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_BLOCK_DIM_X,
289	                )?,
290	                self.device_attribute(
291	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_BLOCK_DIM_Y,
292	                )?,
293	                self.device_attribute(
294	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_BLOCK_DIM_Z,
295	                )?,
296	            ),
297	            max_grid_dim: (
298	                self.device_attribute(
299	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_GRID_DIM_X,
300	                )?,
301	                self.device_attribute(
302	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_GRID_DIM_Y,
303	                )?,
304	                self.device_attribute(
305	                    cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_GRID_DIM_Z,
306	                )?,
307	            ),
308	            max_shared_memory_per_block: self.device_attribute(
309	                cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_SHARED_MEMORY_PER_BLOCK,
310	            )?,
311	        })
312	    }
313	
314	    /// Queries the non-portable opt-in shared-memory limit per block.
315	    ///
316	    /// Typed launch preparation calls this only when static plus dynamic
317	    /// shared memory exceeds the portable limit.
318	    pub fn max_opt_in_shared_memory_per_block(&self) -> Result<u32, DriverError> {
319	        self.device_attribute(
320	            cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MAX_SHARED_MEMORY_PER_BLOCK_OPTIN,
321	        )
322	    }
323	
324	    /// Returns whether this device supports cooperative kernel launches.
325	    pub fn supports_cooperative_launch(&self) -> Result<bool, DriverError> {
326	        self.device_attribute(
327	            cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_COOPERATIVE_LAUNCH,
328	        )
329	        .map(|value| value != 0)
330	    }
331	
332	    /// Returns whether this device supports thread-block cluster launches.
333	    pub fn supports_cluster_launch(&self) -> Result<bool, DriverError> {
334	        self.device_attribute(
335	            cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_CLUSTER_LAUNCH,
336	        )
337	        .map(|value| value != 0)
338	    }
339	
340	    /// Returns the number of streaming multiprocessors on this device.
341	    pub fn multiprocessor_count(&self) -> Result<u32, DriverError> {
342	        self.device_attribute(
343	            cuda_bindings::CUdevice_attribute_enum_CU_DEVICE_ATTRIBUTE_MULTIPROCESSOR_COUNT,
344	        )
345	    }
346	
347	    /// Atomically reads and clears the sticky error state.
348	    ///
349	    /// Returns `Ok(())` if no error was recorded, or the stored
350	    /// [`DriverError`] otherwise. The error is cleared after this call.
351	    pub fn check_err(&self) -> Result<(), DriverError> {
352	        let error_state = self.error_state.swap(0, Ordering::Relaxed);
353	        if error_state == 0 {
354	            Ok(())
355	        } else {
356	            Err(DriverError(error_state))
357	        }
358	    }
359	
360	    /// Records a driver error into the sticky error state.
361	    ///
362	    /// Used during [`Drop`] paths where returning a `Result` is not possible.
363	    /// If `result` is `Err`, the raw error code is stored; subsequent
364	    /// [`check_err`](Self::check_err) or [`bind_to_thread`](Self::bind_to_thread)
365	    /// calls will surface it. A later store overwrites an earlier one.
366	    pub fn record_err<T>(&self, result: Result<T, DriverError>) {
367	        if let Err(err) = result {
368	            self.error_state.store(err.0, Ordering::Relaxed)
369	        }
370	    }
371	}
