595	    /// Queries how many clusters with the exact requested shape can be active
596	    /// on the target device.
597	    ///
598	    /// Unlike [`max_potential_cluster_size`](Self::max_potential_cluster_size),
599	    /// this passes `cluster_dim` as a launch attribute. CUDA therefore checks
600	    /// the concrete shape and any compiled required-cluster dimensions.
601	    pub fn max_active_clusters(
602	        &self,
603	        grid_dim: (u32, u32, u32),
604	        block_dim: (u32, u32, u32),
605	        dynamic_shared_memory_bytes: u32,
606	        cluster_dim: (u32, u32, u32),
607	    ) -> Result<u32, DriverError> {
608	        self.context().bind_to_thread()?;
609	
610	        // CUlaunchAttribute_st is opaque in the generated CUDA 13.2+
611	        // bindings. Its C layout stores the id at offset 0 and the value union
612	        // at offset 8; clusterDim.x/y/z occupy the first three u32 values in
613	        // that union. This matches the launch helpers in cuda-core's root.
614	        let mut cluster_attribute: cuda_bindings::CUlaunchAttribute_st =
615	            unsafe { std::mem::zeroed() };
616	        unsafe {
617	            let base = &mut cluster_attribute as *mut _ as *mut u8;
618	            (base as *mut u32).write(
619	                cuda_bindings::CUlaunchAttributeID_enum_CU_LAUNCH_ATTRIBUTE_CLUSTER_DIMENSION,
620	            );
621	            let dimensions = base.add(8) as *mut u32;
622	            dimensions.write(cluster_dim.0);
623	            dimensions.add(1).write(cluster_dim.1);
624	            dimensions.add(2).write(cluster_dim.2);
625	        }
626	
627	        let config = cuda_bindings::CUlaunchConfig_st {
628	            gridDimX: grid_dim.0,
629	            gridDimY: grid_dim.1,
630	            gridDimZ: grid_dim.2,
631	            blockDimX: block_dim.0,
632	            blockDimY: block_dim.1,
633	            blockDimZ: block_dim.2,
634	            sharedMemBytes: dynamic_shared_memory_bytes,
635	            hStream: std::ptr::null_mut(),
636	            attrs: &mut cluster_attribute,
637	            numAttrs: 1,
638	        };
639	        let mut active_clusters = MaybeUninit::uninit();
640	        unsafe {
641	            cuda_bindings::cuOccupancyMaxActiveClusters(
642	                active_clusters.as_mut_ptr(),
643	                self.cu_function,
644	                &config,
645	            )
646	            .result()?;
647	            u32::try_from(active_clusters.assume_init())
648	                .map_err(|_| DriverError(cuda_bindings::cudaError_enum_CUDA_ERROR_INVALID_VALUE))
649	        }
650	    }
651	
652	    /// Returns the raw `CUfunction` handle.
653	    ///
654	    /// # Safety
655	    ///
656	    /// The returned handle is copied by value, but it is non-owning. It is
657	    /// invalidated if the parent [`CudaModule`] is dropped.
658	    ///
659	    /// Because [`CudaFunction`] holds an [`Arc`] to its parent module, the
660	    /// module cannot be unloaded while `self` is alive. If the raw handle is
661	    /// stored outside the immediate call, the caller must keep this
662	    /// [`CudaFunction`] or another [`Arc`] owning the parent module alive for
663	    /// at least as long as the raw handle is used.
664	    pub unsafe fn cu_function(&self) -> cuda_bindings::CUfunction {
665	        self.cu_function
666	    }
667	}
