781	/// A kernel function and launch configuration whose contract has been checked.
782	///
783	/// Preparation performs all device/function resource queries. Reusing this
784	/// value performs no contract query; it only compares the stream's context
785	/// handle before the normal launch path binds that context.
786	pub struct PreparedLaunch<C: KernelLaunchContract> {
787	    function: CudaFunction,
788	    config: LaunchConfig,
789	    _contract: PhantomData<fn(C) -> C>,
790	}
791	
792	impl<C: KernelLaunchContract> Clone for PreparedLaunch<C> {
793	    fn clone(&self) -> Self {
794	        Self {
795	            function: self.function.clone(),
796	            config: self.config,
797	            _contract: PhantomData,
798	        }
799	    }
800	}
